mapper.select:
SELECT COUNT(1)
FROM [dbo].[lines_stations]
WHERE station_code = #{stationCode, jdbcType=NVARCHAR}

SELECT COUNT(1)
FROM [dbo].[stations]
WHERE id = #{stationId, jdbcType=INTEGER}

SELECT name_zh_tw
FROM [dbo].[stations]
WHERE id = #{stationId, jdbcType=INTEGER}

mapper.update:
UPDATE [dbo].[stations]
name_zh_tw = #{dto.nameZhTw, jdbcType=NVARCHAR}, name_en = #{dto.nameEn, jdbcType=NVARCHAR}, atm = #{dto.atm, jdbcType=NVARCHAR}, nursing_room = #{dto.nursingRoom, jdbcType=NVARCHAR}, diaper_table = #{dto.diaperTable, jdbcType=NVARCHAR}, charging_station = #{dto.chargingStation, jdbcType=NVARCHAR}, ticket_machine = #{dto.ticketMachine, jdbcType=NVARCHAR}, locker = #{dto.locker, jdbcType=NVARCHAR}, drinking_water = #{dto.drinkingWater, jdbcType=NVARCHAR}, restroom = #{dto.restroom, jdbcType=NVARCHAR}, elevator = #{dto.elevator, jdbcType=NVARCHAR}, escalator = #{dto.escalator, jdbcType=NVARCHAR}, updated_at = #{updatedAt, jdbcType=TIMESTAMP}
WHERE id = #{dto.id, jdbcType=INTEGER}

update.foreach:
UPDATE [dbo].[lines_stations]
SET cumulative_time = #{lineStation.cumulativeTime, jdbcType=SMALLINT},
    updated_at      = #{lineStation.updatedAt, jdbcType=TIMESTAMP}
WHERE line_id     = #{lineStation.lineId, jdbcType=SMALLINT}
  AND station_code = #{lineStation.stationCode, jdbcType=NVARCHAR}

mapper.select:
SELECT TOP 1 sf.price
FROM [dbo].[station_fares] sf
INNER JOIN [dbo].[lines_stations] ls_from ON ls_from.station_id = sf.from_station_id
INNER JOIN [dbo].[lines_stations] ls_to   ON ls_to.station_id   = sf.to_station_id
WHERE ls_from.station_code = #{fromStationCode, jdbcType=NVARCHAR}
  AND ls_to.station_code   = #{toStationCode,   jdbcType=NVARCHAR}
  AND sf.fare_type         = #{fareType,         jdbcType=TINYINT}
